```typescript
/**
 * Debounce a function.
 *
 * - Trailing-edge by default: the function is invoked `ms` milliseconds after
 *   the last call.
 * - With `opts.leading === true`: the very first call fires immediately and
 *   any subsequent calls within the `ms` window are suppressed (no trailing
 *   invocation). Once the window expires the next call fires immediately again.
 * - `.cancel()` clears any pending trailing invocation and resets internal
 *   state so the next call behaves like a "first" call.
 * - `this` and argument types are preserved.
 */
export function debounce<T extends (...args: any[]) => void>(
  fn: T,
  ms: number,
  opts?: { leading?: boolean },
): T & { cancel(): void } {
  const leading: boolean = opts?.leading ?? false;

  let timer: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: any[] | null = null;
  let pendingThis: unknown = null;
  let canLeadingFire = true;

  // Use a real function (not arrow) so the call-site `this` is preserved.
  function debounced(this: unknown, ...args: any[]): void {
    pendingArgs = args;
    pendingThis = this;

    if (leading && canLeadingFire) {
      // Fire immediately, then lock the window so subsequent calls are suppressed.
      canLeadingFire = false;
      pendingArgs = null;
      pendingThis = null;
      fn.apply(this, args);
      timer = setTimeout(() => {
        timer = null;
        canLeadingFire = true;
      }, ms);
      return;
    }

    // Trailing-edge path (also used when leading fires but a new call arrives
    // after the leading window: we just refresh and wait again).
    if (timer !== null) {
      clearTimeout(timer);
    }
    timer = setTimeout(() => {
      timer = null;
      if (pendingArgs !== null) {
        const ctx = pendingThis;
        const a = pendingArgs;
        pendingArgs = null;
        pendingThis = null;
        fn.apply(ctx, a);
      }
      canLeadingFire = true;
    }, ms);
  }

  debounced.cancel = function (): void {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
    pendingArgs = null;
    pendingThis = null;
    canLeadingFire = true;
  };

  return debounced as T & { cancel(): void };
}
```

Usage example:

```typescript
const log = debounce((msg: string) => console.log(msg), 200);
log("a"); log("b"); log("c"); // prints "c" after 200ms
log.cancel();                  // clears pending call

const immediate = debounce((n: number) => console.log(n), 200, { leading: true });
immediate(1);  // prints 1 right now
immediate(2);  // suppressed
immediate(3);  // suppressed
// after 200ms, next immediate(...) prints right away again
```

