function debounce<T extends (...args: any[]) => void>(
  fn: T,
  ms: number,
  opts?: { leading?: boolean }
): T & { cancel(): void } {
  const leading = opts?.leading ?? false;
  let timer: ReturnType<typeof setTimeout> | undefined;
  let lastThis: any;
  let lastArgs: any[];

  const debounced = function (this: any, ...args: any[]) {
