      // Leading-edge: fire immediately if no pending timer
      if (!timer) {
        fn.apply(this, args);
        // Set a timer to reset the "in window" state
        timer = setTimeout(() => {
          timer = undefined;
        }, ms);
      }
      // If timer exists, the call is suppressed (no trailing call)
    } else {
      // Trailing-edge (default): reset timer on each call
      if (timer) {
        clearTimeout(timer);
      }
      timer = setTimeout(() => {
        timer = undefined;
        fn.apply(lastThis, lastArgs);
      }, ms);
    }
  };

  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer);
      timer = undefined;
    }
  };

  return debounced as T & { cancel(): void };
}
