      }
      timeoutId = null;
      hasInvokedLeading = false;
    }, ms);
  };

  debounced.cancel = function () {
    if (timeoutId) {
      clearTimeout(timeoutId);
      timeoutId = null;
    }
    hasInvokedLeading = false;
    lastArgs = null;
  };

