```javascript
class Node {
    constructor(key, value, expiresAt) {
        this.key = key;
        this.value = value;
        this.expiresAt = expiresAt;
        this.prev = null;
        this.next = null;
    }
}

class LruTtl {
    constructor(maxSize, defaultTtlMs) {
        this.maxSize = maxSize;
        this.defaultTtlMs = defaultTtlMs;
        this.cache = new Map();

        // Dummy head and tail nodes to simplify linked list operations
        this.head = new Node(null, null, Infinity);
        this.tail = new Node(null, null, Infinity);
        this.head.next = this.tail;
        this.tail.prev = this.head;
    }

    _removeNode(node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
    }

    _addToFront(node) {
        node.next = this.head.next;
        node.prev = this.head;
        this.head.next.prev = node;
        this.head.next = node;
    }

    get(k) {
        if (!this.cache.has(k)) return undefined;

        const node = this.cache.get(k);

        // Lazy expiry: check if the entry has expired
        if (Date.now() > node.expiresAt) {
            this._removeNode(node);
            this.cache.delete(k);
            return undefined;
        }

        // Move to front (mark as most recently used)
        this._removeNode(node);
        this._addToFront(node);

        return node.value;
    }

    set(k, v, ttlMs = this.defaultTtlMs) {
        // If key exists, update value, expiration, and move to front
        if (this.cache.has(k)) {
            const node = this.cache.get(k);
            node.value = v;
            node.expiresAt = Date.now() + ttlMs;

            this._removeNode(node);
            this._addToFront(node);
            return;
        }

        // If cache is full, evict the least recently used (node right before tail)
        if (this.cache.size >= this.maxSize) {
            const lru = this.tail.prev;
            this._removeNode(lru);
            this.cache.delete(lru.key);
        }

        // Create new node, add to map, and add to front of linked list
        const newNode = new Node(k, v, Date.now() + ttlMs);
        this.cache.set(k, newNode);
        this._addToFront(newNode);
    }
