### AWS-style Full Jitter Formula

AWS architecture describes "Full Jitter" as completely randomizing the delay between 0 and the calculated exponential backoff value. The exact formula is:

```text
delay = random_between(0, min(cap, base * 2 ^ attempt))
```

Where:
* `attempt` is the number of the failed attempt (starting at 0).
* `base` is the initial delay in milliseconds.
* `cap` is the maximum delay ceiling in milliseconds.

In JavaScript/TypeScript, this is implemented as:
```typescript
const delay = Math.random() * Math.min(capMs, baseMs * Math.pow(2, attempt));
```

### TypeScript Implementation

Here is the complete implementation including `nextDelayMs` and the `retry` wrapper with `AbortSignal` support:

```typescript
/**
 * Calculates the delay for the next attempt using AWS-style Full Jitter.
 * @param attempt The current attempt number (0-indexed).
 * @param baseMs The base delay in milliseconds.
 * @param capMs The maximum delay cap in milliseconds.
 */
export function nextDelayMs(attempt: number, baseMs: number, capMs: number): number {
    const exponentialDelay = Math.min(capMs, baseMs * Math.pow(2, attempt));
    return Math.random() * exponentialDelay;
}

interface RetryOptions {
    maxAttempts: number;
    baseMs?: number;
    capMs?: number;
    signal?: AbortSignal;
}

/**
 * A sleep function that is abortable via AbortSignal.
 */
function abortableSleep(ms: number, signal?: AbortSignal): Promise<void> {
    return new Promise((resolve, reject) => {
        if (signal?.aborted) {
            return reject(signal.reason ?? new Error('Aborted'));
        }

        const timeout = setTimeout(() => {
            signal?.removeEventListener('abort', onAbort);
            resolve();
        }, ms);

        function onAbort() {
            clearTimeout(timeout);
            reject(signal!.reason ?? new Error('Aborted'));
        }

        if (signal) {
            signal.addEventListener('abort', onAbort, { once: true });
        }
    });
}

/**
 * Retries an asynchronous function with exponential backoff and full jitter.
 * @param fn The function to retry.
 * @param opts Configuration options including maxAttempts, baseMs, capMs, and AbortSignal.
 */
export async function retry<T>(fn: () => Promise<T>, opts: RetryOptions): Promise<T> {
    const { maxAttempts, baseMs = 100, capMs = 10000, signal } = opts;
    let lastError: unknown;

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
        // Check for abort signal before attempting execution
        if (signal?.aborted) {
            throw signal.reason ?? new Error('Aborted');
        }

        try {
            const result = await fn();
            return result;
        } catch (err) {
            lastError = err;

            // If this was the last attempt, do not sleep, just break and throw
            if (attempt === maxAttempts - 1) {
                break;
            }

            const delay = nextDelayMs(attempt, baseMs, capMs);

            try {
                await abortableSleep(delay, signal);
            } catch (abortError) {
                // If the sleep was aborted, throw the abort error immediately
                throw abortError;
            }
        }
    }

    throw lastError;
}
```

