This implementation follows the logic defined in the AWS Architecture Blog's article on **Exponential Backoff and Jitter**.

### The Full Jitter Formula
The "Full Jitter" strategy calculates a maximum backoff value using standard exponential backoff, then picks a random value between **0** and that maximum.

$$sleep = \text{random}(0, \min(cap, base \times 2^{attempt}))$$

---

### TypeScript Implementation

```typescript
/**
 * Calculates the next delay in milliseconds using Exponential Backoff with Full Jitter.
 * 
 * @param attempt - The current retry attempt (0-indexed)
 * @param baseMs - The initial delay in milliseconds
 * @param capMs - The maximum allowed delay
 */
export function nextDelayMs(attempt: number, baseMs: number, capMs: number): number {
  const expBackoff = baseMs * Math.pow(2, attempt);
  const v = Math.min(capMs, expBackoff);
  // Full Jitter: random value between 0 and the exponential cap
  return Math.random() * v;
}

export interface RetryOptions {
  maxAttempts: number;
  baseMs: number;
  capMs: number;
  signal?: AbortSignal;
}

/**
 * A helper to wait for a specific duration, or abort immediately if signal is triggered.
 */
function sleep(ms: number, signal?: AbortSignal): Promise<void> {
  return new Promise((resolve, reject) => {
    if (signal?.aborted) return reject(signal.reason);

    const timeout = setTimeout(resolve, ms);

    signal?.addEventListener('abort', () => {
      clearTimeout(timeout);
      reject(signal.reason);
    }, { once: true });
  });
}

/**
 * Executes an async function with exponential backoff and full jitter.
 */
export async function retry<T>(
  fn: () => Promise<T>,
  opts: RetryOptions
): Promise<T> {
  const { maxAttempts, baseMs, capMs, signal } = opts;

  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      // Check signal before execution
      if (signal?.aborted) throw signal.reason;

      return await fn();
    } catch (error) {
      // If we've exhausted attempts or the signal is aborted, throw
      if (attempt === maxAttempts - 1 || signal?.aborted) {
        throw error;
      }

      const delay = nextDelayMs(attempt, baseMs, capMs);

      // Wait for the calculated jittered delay
      await sleep(delay, signal);
