 * AWS-style exponential backoff with FULL jitter.
 * Returns a delay in milliseconds.
 * 
 * @param attempt - Zero-based attempt number (0 = first retry)
 * @param baseMs - Base delay in milliseconds (e.g., 100)
 * @param capMs - Maximum (absolute) delay cap in milliseconds (e.g., 5000)
 * @returns Delay in milliseconds, uniformly distributed in [0, min(base * 2^attempt, cap)]
 */
export function nextDelayMs(attempt: number, baseMs: number, capMs: number): number {
  if (attempt < 0) throw new RangeError("Attempt must be non-negative");
  if (baseMs <= 0) throw new RangeError("Base delay must be positive");
  if (capMs <= 0) throw new RangeError("Cap delay must be positive");

  const exponentialDelay = baseMs * Math.pow(2, attempt);
  const upperBound = Math.min(exponentialDelay, capMs);
  return Math.random() * upperBound;
}

/**
 * Retries a function with exponential backoff + full jitter.
 * Respects maxAttempts, AbortSignal, and delay generator.
 * 
 * @param fn - Async function to retry (returns Promise<T>)
 * @param opts - Configuration options
 * @returns Promise<T> resolved by successful invocation or throws last error
 */
export async function retry<T>(
  fn: () => Promise<T>,
  opts: {
    baseMs?: number;         // default: 100
    capMs?: number;          // default: 5000
    maxAttempts?: number;    // default: 5 (i.e., 1 initial + 4 retries)
    onRetry?: (err: Error, attempt: number, delay: number) => void;
    signal?: AbortSignal;
  }
): Promise<T> {
  const {
    baseMs = 100,
    capMs = 5000,
    maxAttempts = 5,
    onRetry,
    signal,
  } = opts;

  if (maxAttempts < 1) {
    throw new RangeError("maxAttempts must be ≥ 1");
  }

  let lastError: Error | undefined;

  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      // If using AbortSignal, check it before each attempt
      if (signal?.aborted) {
        throw new Error("Aborted by signal");
      }

      return await fn();
    } catch (err) {
      lastError = err instanceof Error ? err : new Error(String(err));

      // Last attempt: no retry
      if (attempt === maxAttempts - 1) {
        break;
      }

      // Skip delay if aborted during error handling
      if (signal?.aborted) {
        throw lastError;
      }

      // Compute next delay
      const delay = nextDelayMs(attempt, baseMs, capMs);

      // Report delay (optional hook)
      if (onRetry) {
        onRetry(lastError, attempt + 1, delay);
      }

      // Wait with abort-signal awareness
      await sleepWithAbort(delay, signal);
    }
  }

  throw lastError!;
}

/**
 * Helper: sleep with abort signal support.
 */
function sleepWithAbort(ms: number, signal?: AbortSignal): Promise<void> {
  return new Promise((resolve, reject) => {
    const timeoutId = setTimeout(resolve, ms);
    if (signal) {
      const onAbort = () => {
        clearTimeout(timeoutId);
        reject(new Error("Aborted during backoff wait"));
      };
      signal.addEventListener("abort", onAbort, { once: true });
    }
  });
}
```

